import React from "react";
import PointsActivityTable from "@/components/ui/pointsActivityTable";
import NextStatusChart from "@/components/ui/charts/nextStatusChart";
import PointsHistoryChart from "@/components/ui/charts/pointsHistoryChart";
import PointsActivityService from "@/lib/PointsActivityService";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth";
import { prisma } from "@/lib/prisma";

export default async function Home() {
  const session = await getServerSession(authOptions);

  if (!session?.user) {
    return <div className="p-8 text-center text-xl">Please log in to view your profile.</div>;
  }

  const user = session.user;
  const userId = (user as any).id;
  const userName = user.name || "Traveler";
  const userAvatar = user.image || "https://i.pravatar.cc/150?u=" + userId;

  const pointsActivityService = new PointsActivityService();
  const activityData = pointsActivityService.getPointsActivity();
  const currentPoints = pointsActivityService.getCurrentPoints().toLocaleString();
  const currentStatus = pointsActivityService.getCurrentStatus();

  const userBookings = await prisma.booking.findMany({
    where: { userId },
    orderBy: { createdAt: "desc" },
    include: { flight: true },
  });

  return (
    <div className="page-container profile">
      <div className="sidebar-menu">
        <div>
          <img src={userAvatar} className="user-avatar" alt="Avatar" />
          <h3>{userName}</h3>
          <p><strong>Current Status:</strong> {currentStatus}</p>
          <p><strong>Status Points:</strong> {currentPoints}</p>
        </div>

        <div>
          <NextStatusChart />
        </div>
        <div className="mt-6">
          <PointsHistoryChart />
        </div>
      </div>

      <div className="content">
        <div className="profile-card">
          <PointsActivityTable activityData={activityData} />
        </div>

        <div className="profile-card mt-8">
          <h2 className="text-2xl font-bold mb-4">My Bookings</h2>
          {userBookings.length > 0 ? (
            <div className="overflow-x-auto">
              <table className="min-w-full text-left">
                <thead>
                  <tr className="border-b">
                    <th className="pb-2">Flight</th>
                    <th className="pb-2">Route</th>
                    <th className="pb-2">Departure</th>
                    <th className="pb-2">Price</th>
                  </tr>
                </thead>
                <tbody>
                  {userBookings.map((booking) => {
                    const flight = booking.flight;
                    return (
                      <tr key={booking.id} className="border-b">
                        <td className="py-2">{flight ? `${flight.airline} ${flight.flightNumber}` : '—'}</td>
                        <td className="py-2">{flight ? `${flight.from} → ${flight.to}` : '—'}</td>
                        <td className="py-2">{flight ? new Date(flight.departureDate).toLocaleDateString() : '—'}</td>
                        <td className="py-2">{flight?.price ?? '—'}</td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          ) : (
            <p>You have no bookings yet.</p>
          )}
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import { prisma } from '@/lib/prisma';
import Link from 'next/link';

export const dynamic = 'force-dynamic';

export default async function AdminDashboard() {
    const userCount = await prisma.user.count();
    const bookingCount = await prisma.booking.count();
    const cityGuideCount = await prisma.cityGuide.count();

    // Recent bookings
    const recentBookings = await prisma.booking.findMany({
        take: 5,
        orderBy: { createdAt: 'desc' },
        include: { user: true, flight: true }
    });

    return (
        <div className="page-container p-8" style={{ marginTop: '100px' }}>
            <h1 className="text-3xl font-bold mb-6">Admin Dashboard</h1>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8" style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.5rem' }}>
                <div className="bg-white p-6 rounded-lg shadow-md border border-gray-200">
                    <h2 className="text-gray-500 font-semibold mb-2">Total Users</h2>
                    <p className="text-4xl font-bold text-blue-600">{userCount}</p>
                </div>
                <div className="bg-white p-6 rounded-lg shadow-md border border-gray-200">
                    <h2 className="text-gray-500 font-semibold mb-2">Total Bookings</h2>
                    <p className="text-4xl font-bold text-green-600">{bookingCount}</p>
                </div>
                <div className="bg-white p-6 rounded-lg shadow-md border border-gray-200">
                    <h2 className="text-gray-500 font-semibold mb-2">City Guides</h2>
                    <p className="text-4xl font-bold text-purple-600">{cityGuideCount}</p>
                </div>
            </div>

            <div className="mb-8 flex gap-4">
                <Link href="/admin/travelguide" className="inline-block bg-blue-600 text-white px-6 py-2 rounded font-semibold hover:bg-blue-700" style={{ textDecoration: 'none', background: '#2563EB', padding: '0.5rem 1.5rem', borderRadius: '4px', color: 'white' }}>
                    Manage City Guides
                </Link>
            </div>

            <div className="bg-white rounded-lg shadow-md border border-gray-200 overflow-hidden">
                <div className="bg-gray-50 px-6 py-4 border-b border-gray-200">
                    <h2 className="font-bold text-lg text-gray-800">Recent Bookings</h2>
                </div>
                <div className="p-0">
                    {recentBookings.length > 0 ? (
                        <table className="min-w-full divide-y divide-gray-200" style={{ width: '100%', textAlign: 'left', borderCollapse: 'collapse' }}>
                            <thead className="bg-gray-50">
                                <tr>
                                    <th className="px-6 py-3 text-xs font-medium text-gray-500 uppercase tracking-wider border-b">User</th>
                                    <th className="px-6 py-3 text-xs font-medium text-gray-500 uppercase tracking-wider border-b">Flight</th>
                                    <th className="px-6 py-3 text-xs font-medium text-gray-500 uppercase tracking-wider border-b">Route</th>
                                    <th className="px-6 py-3 text-xs font-medium text-gray-500 uppercase tracking-wider border-b">Date</th>
                                </tr>
                            </thead>
                            <tbody className="bg-white divide-y divide-gray-200">
                                {recentBookings.map((booking) => {
                                    const flight = booking.flight;
                                    return (
                                        <tr key={booking.id}>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 border-b">{booking.user?.name || booking.user?.email || 'Guest'}</td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 border-b">{flight ? `${flight.airline} ${flight.flightNumber}` : '—'}</td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 border-b">{flight ? `${flight.from} → ${flight.to}` : '—'}</td>
                                            <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 border-b">{new Date(booking.createdAt).toLocaleDateString()}</td>
                                        </tr>
                                    );
                                })}
                            </tbody>
                        </table>
                    ) : (
                        <div className="p-6 text-gray-500">No recent bookings.</div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client"
import React from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { useSession, signOut } from 'next-auth/react';

const TitleBar: React.FC = () => {
    const pathname = usePathname();
    const { data: session } = useSession();

    const pageTitles: { [key: string]: string } = {
        '/book': 'Book Flight',
        '/checkin': 'Check-In',
        '/travelguide': 'Travel Guide',
        '/profile': 'Profile',
        '/admin': 'Admin Dashboard',
        '/admin/travelguide': 'Manage City Guides',
    };

    const pageTitle = pageTitles[pathname] || '';
    const userAvatar = session?.user?.image || "/img/my-profile-photo.jpg";
    const isAdmin = (session?.user as any)?.role === 'ADMIN';

    return (
        <header className={pathname?.startsWith('/admin') ? 'admin-header' : ''}>
            <div className="logo">
                <Link href="/" style={{ display: 'flex', alignItems: 'center', gap: '8px', textDecoration: 'none' }}>
                    <img src="/img/logo.svg" alt="Gemini Airways" width="32" height="32" />
                    <span style={{ fontWeight: 'bold', fontSize: '1.2rem' }}>Gemini Airways</span>
                </Link>
                <span>{pageTitle}</span>
            </div>
            <nav>
                <ul style={{ display: 'flex', alignItems: 'center', gap: '2rem' }}>
                    {!pathname?.startsWith('/admin') && (
                        <>
                            <li className={pathname === '/book' ? 'selected' : ''}>
                                <Link href="/book">Book Flight</Link>
                            </li>
                            <li className={pathname === '/checkin' ? 'selected' : ''}>
                                <Link href="#">Check-In</Link>
                            </li>
                            <li className={pathname === '/travelguide' ? 'selected' : ''}>
                                <Link href="/travelguide">Travel Guide</Link>
                            </li>
                        </>
                    )}

                    {isAdmin && (
                        <li className={pathname === '/admin' ? 'selected' : ''}>
                            <Link href="/admin">Admin</Link>
                        </li>
                    )}

                    {session ? (
                        <li style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                            <div className="avatar" style={{ display: 'flex', alignItems: 'center' }}>
                                <Link href="/profile" style={{ display: 'flex' }}>
                                    <img src={userAvatar} width="32" height="32" alt="Profile" style={{ borderRadius: '50%', display: 'block' }} />
                                </Link>
                            </div>
                            <button onClick={() => signOut()} style={{ background: 'none', border: 'none', padding: 0, height: 'auto', width: 'auto', color: pathname?.startsWith('/admin') ? 'white' : 'inherit', cursor: 'pointer', fontWeight: 'bold', fontSize: 'inherit', fontFamily: 'inherit' }}>
                                Sign Out
                            </button>
                        </li>
                    ) : (
                        <>
                            <li>
                                <Link href="/login" style={{ color: pathname?.startsWith('/admin') ? 'white' : 'inherit', fontWeight: 'bold' }}>
                                    Sign In
                                </Link>
                            </li>
                            <li>
                                <Link href="/signup" style={{ color: pathname?.startsWith('/admin') ? 'white' : 'inherit', fontWeight: 'bold' }}>
                                    Sign Up
                                </Link>
                            </li>
                        </>
                    )}
                </ul>
            </nav>
        </header>
    );
};

export default TitleBar;

