"use client"

import * as React from "react"
import { CartesianGrid, Line, LineChart, XAxis, YAxis } from "recharts"

import {
    Card,
    CardContent,
    CardHeader,
    CardTitle,
    CardDescription,
} from "@/components/ui/card"
import {
    ChartConfig,
    ChartContainer,
    ChartTooltip,
    ChartTooltipContent,
} from "@/components/ui/chart"
import PointsActivityService from "@/lib/PointsActivityService"

const chartConfig = {
    points: {
        label: "Points",
        color: "hsl(var(--chart-1))",
    },
} satisfies ChartConfig

export default function PointsHistoryChart() {
    const [chartData, setChartData] = React.useState<any[]>([])

    React.useEffect(() => {
        const service = new PointsActivityService()
        const data = service.getMonthlyPointsActivity()
        setChartData(data)
    }, [])

    return (
        <Card>
            <CardHeader>
                <CardTitle>Points History</CardTitle>
                <CardDescription>Monthly points accumulation over the last year</CardDescription>
            </CardHeader>
            <CardContent>
                <ChartContainer config={chartConfig} className="min-h-[200px] w-full">
                    <LineChart
                        accessibilityLayer
                        data={chartData}
                        margin={{
                            left: 12,
                            right: 12,
                        }}
                    >
                        <CartesianGrid vertical={false} />
                        <XAxis
                            dataKey="date"
                            tickLine={false}
                            axisLine={false}
                            tickMargin={8}
                        />
                        <YAxis
                            tickLine={false}
                            axisLine={false}
                            tickMargin={8}
                            width={40}
                        />
                        <ChartTooltip
                            cursor={false}
                            content={<ChartTooltipContent hideLabel />}
                        />
                        <Line
                            dataKey="points"
                            type="natural"
                            stroke="var(--color-points)"
                            strokeWidth={2}
                            dot={{
                                fill: "var(--color-points)",
                            }}
                            activeDot={{
                                r: 6,
                            }}
                        />
                    </LineChart>
                </ChartContainer>
            </CardContent>
        </Card>
    )
}

"use client"

import * as React from "react"
import { Label, Pie, PieChart } from "recharts"

import {
  CardContent,
} from "@/components/ui/card"
import {
  ChartConfig,
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
} from "@/components/ui/chart"

export const description = "Status Progress"

const chartData = [
  { status: "Bronze", points: 300, fill: "var(--color-bronze)" },
  { status: "Silver", points: 500, fill: "var(--color-silver)" },
  { status: "Gold", points: 300, fill: "var(--color-gold)" },
  { status: "Remaining Gold", points: 700, fill: "var(--color-notgold)" },
  { status: "Remaining Platinum", points: 1000, fill: "var(--color-notplatinum)" },
]

const chartConfig = {
    bronze: {
        label: "Bronze",
        color: "hsl(38, 43%, 54%)"
    },
    silver: {
        label: "Silver", // silver color
        color: "hsl(60, 0%, 50%)"
    },
    gold: {
        label: "Gold",
        color: "hsl(57, 81%, 42%)"
    },
    notgold: {
        label: "Remaining Gold",
        color: "hsl(57, 15%, 85%)"
    },
    notplatinum: {
        label: "Remaining Platinum",
        color: "hsl(0, 0%, 90%)"
    }
} satisfies ChartConfig

export default function NextStatusChart() {
  const totalpoints = React.useMemo(() => {
    return chartData.reduce((acc, curr) => acc + curr.points, 0)
  }, [])

  return (
   <>
      <CardContent>
        <ChartContainer
          config={chartConfig}
          className="mx-auto aspect-square max-h-[350px]"
        >
          <PieChart>
            <ChartTooltip
              cursor={false}
              content={<ChartTooltipContent hideLabel />}
            />
            <Pie
              data={chartData}
              dataKey="points"
              nameKey="status"
              innerRadius={30}
              strokeWidth={5}
            >
              <Label
                content={({ viewBox }) => {
                  if (viewBox && "cx" in viewBox && "cy" in viewBox) {
                    return (
                      <text
                        x={viewBox.cx}
                        y={viewBox.cy}
                        textAnchor="middle"
                        dominantBaseline="middle"
                      >
                        <tspan
                          x={viewBox.cx}
                          y={viewBox.cy}
                          className="fill-foreground text-3xl font-bold"
                        >
                          {totalpoints.toLocaleString()}
                        </tspan>
                        <tspan
                          x={viewBox.cx}
                          y={(viewBox.cy || 0) + 24}
                          className="fill-muted-foreground"
                        >
                          points
                        </tspan>
                      </text>
                    )
                  }
                }}
              />
            </Pie>
          </PieChart>
        </ChartContainer>
      </CardContent>
        <div>
          1,700 points until Platinum
        </div>

      </>
  )
}

