import { NextAuthOptions } from 'next-auth';
import { Adapter } from 'next-auth/adapters';
import CredentialsProvider from 'next-auth/providers/credentials';
import { PrismaAdapter } from '@auth/prisma-adapter';
import { prisma } from '@/lib/prisma';
import bcrypt from 'bcryptjs';

// A valid bcrypt hash of a throwaway value, used only to equalize response
// timing when no matching user exists (anti-enumeration). It is never a real
// credential and never matches any user-supplied password.
const DUMMY_PASSWORD_HASH = '$2b$10$m5cSUIfLL/REDACTED.YOCKKxBtS';

export const authOptions: NextAuthOptions = {
    // @auth/prisma-adapter is typed against @auth/core's Adapter, which is
    // structurally compatible with next-auth v4's Adapter but nominally distinct.
    adapter: PrismaAdapter(prisma) as Adapter,
    providers: [
        CredentialsProvider({
            name: 'Credentials',
            credentials: {
                email: { label: 'Email', type: 'email', placeholder: 'user@example.com' },
                password: { label: 'Password', type: 'password' },
            },
            async authorize(credentials) {
                // Single generic message for every failure mode so the response
                // never reveals whether an account with this email exists.
                const INVALID = 'Invalid email or password';

                if (!credentials?.email || !credentials?.password) {
                    throw new Error(INVALID);
                }

                const user = await prisma.user.findUnique({
                    where: { email: credentials.email },
                });

                // Always run a bcrypt comparison — against the real hash when the
                // user exists, otherwise a dummy — so response time does not leak
                // account existence (timing-based enumeration).
                const passwordHash = user?.password ?? DUMMY_PASSWORD_HASH;
                const isPasswordValid = await bcrypt.compare(credentials.password, passwordHash);

                if (!user || !user.password || !isPasswordValid) {
                    throw new Error(INVALID);
                }

                // Return only non-sensitive fields (never the password hash).
                return {
                    id: user.id,
                    email: user.email,
                    name: user.name,
                    image: user.image,
                    role: user.role,
                };
            },
        }),
    ],
    session: {
        strategy: 'jwt',
    },
    pages: {
        signIn: '/login', // User custom login page
        newUser: '/signup' // New users directed to sign up page
    },
    callbacks: {
        async jwt({ token, user, account }) {
            if (user) {
                token.id = user.id;
                token.role = (user as any).role;
            }
            return token;
        },
        async session({ session, token }) {
            if (session.user) {
                (session.user as any).id = token.id as string;
                (session.user as any).role = token.role as string;
            }
            return session;
        },
    },
};

'use server'

import { revalidatePath } from 'next/cache';
import TravelGuideService from '@/lib/TravelGuideService';
import FlightBookingService from '@/lib/FlightBookingService';
import CityGuide from '@/lib/types/CityGuide';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth';
import { prisma } from '@/lib/prisma';

const travelGuideService = new TravelGuideService();
const flightBookingService = new FlightBookingService();

export async function saveCityGuideAction(cityGuide: CityGuide) {
    const session = await getServerSession(authOptions);
    if ((session?.user as any)?.role !== 'ADMIN') throw new Error("Unauthorized");

    const result = await travelGuideService.saveCityGuide(cityGuide);
    revalidatePath('/admin/travelguide');
    revalidatePath('/travelguide');
    return result;
}

export async function deleteCityGuideAction(cityGuideId: number) {
    const session = await getServerSession(authOptions);
    if ((session?.user as any)?.role !== 'ADMIN') throw new Error("Unauthorized");

    await prisma.cityGuide.delete({
        where: { id: cityGuideId }
    });
    revalidatePath('/admin/travelguide');
    revalidatePath('/travelguide');
}

export async function searchFlightsAction(from: string, to: string) {
    // Mock search by just returning all flights so users can see data regardless of selection
    return await prisma.flight.findMany();
}

export async function bookFlightAction(bookingData: { flightId?: number }) {
    const session = await getServerSession(authOptions);
    const userId = session?.user ? (session.user as any).id : undefined;

    return await flightBookingService.bookFlight({
        flightId: bookingData.flightId,
        userId
    });
}

export async function toggleFavoriteCityGuideAction(cityGuideId: number) {
    const session = await getServerSession(authOptions);
    const userId = session?.user ? (session.user as any).id : undefined;
    if (!userId) throw new Error("Unauthorized");

    const existing = await prisma.userFavorite.findUnique({
        where: { userId_cityGuideId: { userId, cityGuideId } }
    });

    if (existing) {
        await prisma.userFavorite.delete({
            where: { id: existing.id }
        });
        return { isFavorite: false };
    } else {
        await prisma.userFavorite.create({
            data: { userId, cityGuideId }
        });
        return { isFavorite: true };
    }
}

export async function submitCityGuideReviewAction(cityGuideId: number, rating: number, content: string) {
    const session = await getServerSession(authOptions);
    const userId = session?.user ? (session.user as any).id : undefined;
    if (!userId) throw new Error("Unauthorized");

    return await prisma.review.create({
        data: {
            userId,
            cityGuideId,
            rating,
            content
        }
    });
}

